class Solution {
    public int[] shortestAlternatingPaths(int n, int[][] redEdges, int[][] blueEdges) {
        List<Integer>[] redGraph = new List[n];
        List<Integer>[] blueGraph = new List[n];
        for (int i = 0; i < n; i++) {
            redGraph[i] = new ArrayList<>();
            blueGraph[i] = new ArrayList<>();
        }
        for (int[] edge : redEdges) {
            redGraph[edge[0]].add(edge[1]);
        }
        for (int[] edge : blueEdges) {
            blueGraph[edge[0]].add(edge[1]);
        }
        int[] answer = new int[n];
        Arrays.fill(answer, -1);
        answer[0] = 0;
        Queue<int[]> queue = new LinkedList<>();
        queue.offer(new int[]{0, 0, 0}); // node, distance, lastColor
        while (!queue.isEmpty()) {
            int[] curr = queue.poll();
            int node = curr[0];
            int dist = curr[1];
            int lastColor = curr[2];
            if (answer[node] != -1 && answer[node] <= dist) {
                continue;
            }
            answer[node] = dist;
            if (lastColor == 0) {
                for (int next : blueGraph[node]) {
                    queue.offer(new int[]{next, dist + 1, 1});
                }
            } else {
                for (int next : redGraph[node]) {
                    queue.offer(new int[]{next, dist + 1, 0});
                }
            }
        }
        return answer;
    }
}
